import{_ as n,C as i,o as l,c as d,j as t,a,E as o,a3 as s}from"./chunks/framework.D3_W51PR.js";const k=JSON.parse('{"title":"Shell-Tab-Vervollständigung","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/shell-completion.md","filePath":"de/advanced/shell-completion.md"}'),c={name:"de/advanced/shell-completion.md"},h={id:"shell-tab-vervollstandigung",tabindex:"-1"};function g(u,e,m,b,p,v){const r=i("VersionBadge");return l(),d("div",null,[t("h1",h,[e[0]||(e[0]=a("Shell-Tab-Vervollständigung ",-1)),o(r,{v:"0.10.0"}),e[1]||(e[1]=a()),e[2]||(e[2]=t("a",{class:"header-anchor",href:"#shell-tab-vervollstandigung","aria-label":'Permalink to "Shell-Tab-Vervollständigung <VersionBadge v="0.10.0" />"'},"​",-1))]),e[3]||(e[3]=s('<p>amoxide vervollständigt Profilnamen, Aliasnamen, Subcommand-Alias-Segmente und Variablennamen mit Tab — überall dort, wo du sie eingeben würdest.</p><h2 id="was-wird-wo-vervollstandigt" tabindex="-1">Was wird wo vervollständigt <a class="header-anchor" href="#was-wird-wo-vervollstandigt" aria-label="Permalink to &quot;Was wird wo vervollständigt&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Du tippst</th><th>Tab liefert</th></tr></thead><tbody><tr><td><code>am use &lt;TAB&gt;</code></td><td>aktive und inaktive Profilnamen</td></tr><tr><td><code>am profile use &lt;TAB&gt;</code>, <code>am profile remove &lt;TAB&gt;</code></td><td>Profilnamen</td></tr><tr><td><code>am remove &lt;TAB&gt;</code></td><td>Aliasnamen aus dem aktuellen Kontext (global + aktive Profile + Projekt)</td></tr><tr><td><code>am remove -p rust &lt;TAB&gt;</code></td><td>nur Aliase aus dem Profil <code>rust</code></td></tr><tr><td><code>am remove -g &lt;TAB&gt;</code></td><td>nur globale Aliase</td></tr><tr><td><code>am remove -l &lt;TAB&gt;</code></td><td>nur Projekt-Aliase (lokal)</td></tr><tr><td><code>am remove jj --sub &lt;TAB&gt;</code></td><td>das nächste Segment einer Subcommand-Alias-Kette (z. B. <code>b</code>, <code>ab</code>)</td></tr><tr><td><code>am var get &lt;TAB&gt;</code>, <code>am var unset &lt;TAB&gt;</code></td><td>Variablennamen aus dem aktuellen Kontext, durch <code>-p</code> / <code>-l</code> / <code>-g</code> eingeschränkt</td></tr><tr><td><code>am export -p &lt;TAB&gt;</code>, <code>am import -p &lt;TAB&gt;</code>, <code>am share -p &lt;TAB&gt;</code></td><td>Profilnamen</td></tr></tbody></table><h2 id="wie-es-funktioniert" tabindex="-1">Wie es funktioniert <a class="header-anchor" href="#wie-es-funktioniert" aria-label="Permalink to &quot;Wie es funktioniert&quot;">​</a></h2><p><code>am init &lt;shell&gt;</code> enthält eine einzeilige Registrierung, die amoxide in das Vervollständigungssystem deiner Shell einbindet. Wenn du Tab drückst, fragt die Shell <code>am</code>, was an dieser Stelle gültig ist. Die Abfrage läuft gegen deine aktive Konfiguration, also bleiben Vervollständigungen ohne Cache-Invalidierung aktuell.</p><p>Nichts zusätzlich zu installieren oder zu sourcen. Wenn du <code>am setup</code> bereits ausgeführt hast, wird die Vervollständigung beim nächsten Öffnen einer Shell aktiv.</p><h2 id="unterstutzte-shells" tabindex="-1">Unterstützte Shells <a class="header-anchor" href="#unterstutzte-shells" aria-label="Permalink to &quot;Unterstützte Shells&quot;">​</a></h2><ul><li><strong>Bash</strong> (3.2+)</li><li><strong>Zsh</strong></li><li><strong>Fish</strong></li><li><strong>PowerShell</strong> (5.1 + 7)</li><li><strong>Brush</strong> — verwendet die Bash-Anbindung</li></ul><p>Nushell wird noch nicht unterstützt; der Upstream-Stand ist in <a href="https://github.com/clap-rs/clap/pull/5841" target="_blank" rel="noreferrer"><code>clap-rs/clap#5841</code></a>.</p><h2 id="fehlerbehebung" tabindex="-1">Fehlerbehebung <a class="header-anchor" href="#fehlerbehebung" aria-label="Permalink to &quot;Fehlerbehebung&quot;">​</a></h2><h3 id="vervollstandigung-funktioniert-nach-dem-upgrade-nicht" tabindex="-1">Vervollständigung funktioniert nach dem Upgrade nicht <a class="header-anchor" href="#vervollstandigung-funktioniert-nach-dem-upgrade-nicht" aria-label="Permalink to &quot;Vervollständigung funktioniert nach dem Upgrade nicht&quot;">​</a></h3><p>Öffne eine neue Shell oder führe in der aktuellen Sitzung erneut <code>eval &quot;$(am init &lt;shell&gt;)&quot;</code> aus. Die Registrierung wird über die <code>am init</code>-Ausgabe geladen; alte Shells sehen sie erst nach erneuter Auswertung.</p><h3 id="registrierung-ist-da-aber-tab-passiert-nichts" tabindex="-1">Registrierung ist da, aber Tab passiert nichts <a class="header-anchor" href="#registrierung-ist-da-aber-tab-passiert-nichts" aria-label="Permalink to &quot;Registrierung ist da, aber Tab passiert nichts&quot;">​</a></h3><p>Prüfe die Shell-Version (bash ≥ 3.2, zsh, fish, powershell 5.1+). Bei bash zusätzlich sicherstellen, dass kein anderes Tool mit <code>complete -F</code> amoxides Registrierung überschreibt. Das Paket <code>bash-completion</code> ist nicht nötig.</p>',14))])}const T=n(c,[["render",g]]);export{k as __pageData,T as default};
